<?php
declare(strict_types=1);
if($path!=='/admin/booking-engine')return;if(!(user()['is_admin']??false)){http_response_code(403);exit('Forbidden');}
if($method==='POST'){verify_csrf();if(post('action')==='mapping'){foreach((array)post('providers',[]) as $id=>$external)db()->prepare('UPDATE booking_calendars SET external_provider_id=? WHERE id=?')->execute([(int)$external?:null,(int)$id]);foreach((array)post('services',[]) as $id=>$external)db()->prepare('UPDATE booking_meeting_types SET external_service_id=? WHERE id=?')->execute([(int)$external?:null,(int)$id]);audit('update','booking_engine_mapping');flash('success','Booking mappings updated.');redirect('/admin/booking-engine');}$engine=post('booking_engine')==='easyappointments'?'easyappointments':'native';$url=rtrim(trim((string)post('easyappointments_url')),'/');if($url!==''&&!filter_var($url,FILTER_VALIDATE_URL)){flash('error','Enter a valid Easy!Appointments URL.');redirect('/admin/booking-engine');}$values=['booking_engine'=>$engine,'easyappointments_url'=>$url];if(trim((string)post('easyappointments_api_token'))!=='')$values['easyappointments_api_token_enc']=encrypt_secret(trim((string)post('easyappointments_api_token')));$save=db()->prepare('INSERT INTO app_settings(setting_key,setting_value) VALUES(?,?) ON DUPLICATE KEY UPDATE setting_value=VALUES(setting_value)');foreach($values as $key=>$value)$save->execute([$key,$value]);audit('update','booking_engine',null,['engine'=>$engine,'url'=>$url,'token_changed'=>isset($values['easyappointments_api_token_enc'])]);if(post('action')==='test'){try{ea_request('GET','services',['length'=>1]);flash('success','Easy!Appointments connection succeeded.');}catch(Throwable $e){flash('error',$e->getMessage());}}else flash('success','Booking engine settings saved.');redirect('/admin/booking-engine');}
$s=app_settings();$calendars=db()->query('SELECT id,name,external_provider_id FROM booking_calendars ORDER BY name')->fetchAll();$types=db()->query('SELECT id,name,external_service_id FROM booking_meeting_types ORDER BY name')->fetchAll();layout('Booking engine',function()use($s,$calendars,$types){?><h1>Booking engine</h1><form class="card" method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><label>Engine<select name="booking_engine"><option value="native">OpenCRM Native</option><option value="easyappointments" <?=$s['booking_engine']==='easyappointments'?'selected':''?>>Easy!Appointments</option></select></label><label>Easy!Appointments base URL<input type="url" name="easyappointments_url" value="<?=e($s['easyappointments_url'])?>" placeholder="https://rapidanalyticssoftware.com/scheduler"></label><label>API bearer token<input type="password" name="easyappointments_api_token" autocomplete="new-password" placeholder="<?=app_setting('easyappointments_api_token_enc')?'Stored — leave blank to keep':'Paste API token'?>"></label><p class="muted">The token is encrypted and never displayed again. OpenCRM calls the API server-side; credentials are never exposed to booking visitors.</p><div class="actions"><button name="action" value="save">Save settings</button><button class="secondary" name="action" value="test">Save and test connection</button></div></form><form class="card" method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><input type="hidden" name="action" value="mapping"><h2>Provider and service mapping</h2><div class="grid"><div><h3>Calendars → providers</h3><?php foreach($calendars as $c):?><label><?=e($c['name'])?><input type="number" min="1" name="providers[<?=$c['id']?>]" value="<?=e($c['external_provider_id'])?>" placeholder="Easy!Appointments provider ID"></label><?php endforeach?></div><div><h3>Meeting types → services</h3><?php foreach($types as $t):?><label><?=e($t['name'])?><input type="number" min="1" name="services[<?=$t['id']?>]" value="<?=e($t['external_service_id'])?>" placeholder="Easy!Appointments service ID"></label><?php endforeach?></div></div><button>Save mappings</button></form><?php });exit;
